const raw = $input.first().json;
const body = (raw.body && raw.body.action) ? raw.body : raw;
const { action, sessionId } = body;

const store = $getWorkflowStaticData('global');

// ── Site config actions (no sessionId needed) ──
if (action === 'getSiteConfig') {
  const cfg = store.siteConfig || {};
  return [{ json: {
    basePrompt: cfg.basePrompt || '',
    courses: cfg.courses || []
  }}];
}

if (action === 'addReport') {
  if (!store.reports) store.reports = [];
  store.reports.unshift({ id: Date.now(), text: body.text || '', ts: new Date().toISOString(), read: false });
  if (store.reports.length > 50) store.reports = store.reports.slice(0, 50);
  return [{ json: { ok: true } }];
}

if (action === 'setSiteConfig') {
  if (!store.siteConfig) store.siteConfig = {};
  if (typeof body.basePrompt === 'string') store.siteConfig.basePrompt = body.basePrompt;
  if (Array.isArray(body.courses)) store.siteConfig.courses = body.courses;
  return [{ json: { ok: true } }];
}


if (action === 'savePending') {
  if (!store.pending) store.pending = {};
  store.pending[body.id] = body.text;
  return [{ json: { ok: true } }];
}

if (action === 'getPending') {
  const text = (store.pending || {})[body.id] || null;
  return [{ json: { text } }];
}

if (action === 'getChannelSettings') {
  return [{ json: store.channelSettings || { autoPost9: false, autoPost13: true, autoPost19: true } }];
}

if (action === 'setChannelSettings') {
  store.channelSettings = Object.assign(store.channelSettings || {}, body.settings || {});
  return [{ json: { ok: true } }];
}

// ── File storage actions ──
if (action === 'addFile') {
  if (!store.files) store.files = [];
  store.files.unshift({
    id: body.id || 'f_' + Date.now(),
    chatId: body.chatId || '',
    name: body.name || '',
    type: body.type || 'document',
    mime: body.mime || '',
    size: body.size || 0,
    path: body.path || '',
    description: body.description || '',
    tags: body.tags || [],
    summary: body.summary || '',
    facts: body.facts || [],
    ts: new Date().toISOString()
  });
  if (store.files.length > 500) store.files = store.files.slice(0, 500);
  return [{ json: { ok: true } }];
}

if (action === 'searchFiles') {
  const q = (body.query || '').toLowerCase();
  const chatId = body.chatId || '';
  const all = (store.files || []).filter(f => !chatId || String(f.chatId) === String(chatId));
  if (!q) return [{ json: { files: all.slice(0, 20) } }];
  const words = q.split(/\s+/);
  const scored = all.map(f => {
    const hay = (f.name + ' ' + f.description + ' ' + (f.tags || []).join(' ')).toLowerCase();
    const hits = words.filter(w => hay.includes(w)).length;
    return { ...f, score: hits };
  }).filter(f => f.score > 0).sort((a, b) => b.score - a.score);
  return [{ json: { files: scored.slice(0, 10) } }];
}

if (action === 'getFiles') {
  const chatId = body.chatId || '';
  const all = (store.files || []).filter(f => !chatId || String(f.chatId) === String(chatId));
  return [{ json: { files: all } }];
}

// Semantic search across knowledge base (summary + facts + description + tags)
if (action === 'searchKnowledge') {
  const q = (body.query || '').toLowerCase();
  const chatId = body.chatId || '';
  const all = (store.files || []).filter(f => !chatId || String(f.chatId) === String(chatId));
  if (!q) return [{ json: { results: all.slice(0, 5).map(f => ({ name: f.name, description: f.description, summary: f.summary, facts: f.facts })) } }];
  const words = q.split(/\s+/).filter(w => w.length > 2);
  const scored = all.map(f => {
    const hay = (f.name + ' ' + f.description + ' ' + (f.tags || []).join(' ') + ' ' + (f.summary || '') + ' ' + (f.facts || []).join(' ')).toLowerCase();
    const hits = words.filter(w => hay.includes(w)).length;
    return { ...f, score: hits };
  }).filter(f => f.score > 0).sort((a, b) => b.score - a.score);
  const results = scored.slice(0, 5).map(f => ({ name: f.name, description: f.description, summary: f.summary, facts: f.facts, ts: f.ts }));
  return [{ json: { results, total: scored.length } }];
}

// ── Email context actions ──
if (action === 'addEmailContext') {
  if (!store.emails) store.emails = [];
  store.emails.unshift({
    id: body.emailId || 'em_' + Date.now(),
    from: body.from || '',
    subject: body.subject || '',
    body: (body.body || '').slice(0, 3000),
    date: body.date || new Date().toISOString(),
    summary: body.summary || ''
  });
  if (store.emails.length > 50) store.emails = store.emails.slice(0, 50);
  return [{ json: { ok: true } }];
}

if (action === 'searchEmails') {
  const q = (body.query || '').toLowerCase();
  const all = store.emails || [];
  if (!q) return [{ json: { emails: all.slice(0, 5) } }];
  const words = q.split(/\s+/);
  const scored = all.map(e => {
    const hay = (e.from + ' ' + e.subject + ' ' + e.body + ' ' + e.summary).toLowerCase();
    const hits = words.filter(w => hay.includes(w)).length;
    return { ...e, score: hits };
  }).filter(e => e.score > 0).sort((a, b) => b.score - a.score);
  return [{ json: { emails: scored.slice(0, 5) } }];
}

if (action === 'getEmails') {
  return [{ json: { emails: (store.emails || []).slice(0, 20) } }];
}

// ── Alfa-Bank transactions (global, not per-session) ──
function extractMerchant(purpose) {
  if (!purpose) return null;
  const m = purpose.match(/\\([^\\]+?)\s+по\s+чеку/i);
  if (m) return m[1].trim();
  const m2 = purpose.match(/\b([A-ZА-Я0-9][A-ZА-Я0-9_\-\.]{3,})\b/);
  return m2 ? m2[1] : null;
}

if (action === 'addAlfaTx') {
  if (!store.alfaTx) store.alfaTx = [];
  const tx = body.tx;
  if (tx && tx.id) {
    if (!tx.merchant) tx.merchant = extractMerchant(tx.purpose);
    // Apply rules if no category yet
    if (!tx.category && tx.purpose) {
      const upP = tx.purpose.toUpperCase();
      const rule = (store.alfaRules || []).find(r => r.key && upP.includes(r.key.toUpperCase()));
      if (rule) { tx.category = rule.category; tx.categorySource = 'rule'; }
    } else if (tx.category) {
      tx.categorySource = tx.categorySource || 'auto';
    }
    const exists = store.alfaTx.find(t => t.id === tx.id);
    if (!exists) {
      store.alfaTx.unshift(tx);
      if (store.alfaTx.length > 5000) store.alfaTx = store.alfaTx.slice(0, 5000);
    }
  }
  return [{ json: { ok: true, total: (store.alfaTx || []).length, appliedCategory: tx?.category || null } }];
}

if (action === 'getAlfaTx') {
  let txs = store.alfaTx || [];
  if (body.monthKey) txs = txs.filter(t => t.monthKey === body.monthKey);
  if (body.onlyUncategorized) txs = txs.filter(t => !t.category);
  return [{ json: { txs } }];
}

if (action === 'setAlfaCategory') {
  const tx = (store.alfaTx || []).find(t => t.id === body.txId);
  if (!tx) return [{ json: { ok: false, error: 'tx not found' } }];
  tx.category = body.category || null;
  tx.categorySource = 'manual';
  // Save rule derived from merchant (default: yes)
  if (body.rememberRule !== false && body.category) {
    const key = body.ruleKey || tx.merchant || extractMerchant(tx.purpose);
    if (key && key.length >= 3) {
      if (!store.alfaRules) store.alfaRules = [];
      store.alfaRules = store.alfaRules.filter(r => r.key !== key);
      store.alfaRules.unshift({ key, category: body.category, ts: new Date().toISOString() });
      if (store.alfaRules.length > 500) store.alfaRules = store.alfaRules.slice(0, 500);
      // Also retroactively apply rule to past uncategorized txs with same merchant
      let retro = 0;
      for (const t of store.alfaTx || []) {
        if (!t.category && t.purpose && t.purpose.toUpperCase().includes(key.toUpperCase())) {
          t.category = body.category;
          t.categorySource = 'rule';
          retro++;
        }
      }
      return [{ json: { ok: true, ruleKey: key, retro } }];
    }
  }
  return [{ json: { ok: true } }];
}

if (action === 'getAlfaRules') {
  return [{ json: { rules: store.alfaRules || [] } }];
}

if (action === 'removeAlfaTx') {
  const before = (store.alfaTx || []).length;
  if (store.alfaTx && body.txId) {
    const removed = store.alfaTx.find(t => t.id === body.txId);
    store.alfaTx = store.alfaTx.filter(t => t.id !== body.txId);
    return [{ json: { ok: true, removed: !!removed, txDescr: removed ? (removed.amount + ' ₽ · ' + (removed.purpose || '').slice(0, 40)) : null } }];
  }
  return [{ json: { ok: false, error: 'no txId or store empty' } }];
}

// ── Bubbleplan tasks (synced from external) ──
if (action === 'syncBubbles') {
  store.bubbles = Array.isArray(body.bubbles) ? body.bubbles : [];
  store.bubblesSyncedAt = new Date().toISOString();
  return [{ json: { ok: true, count: store.bubbles.length, syncedAt: store.bubblesSyncedAt } }];
}

if (action === 'getBubbles') {
  let bubbles = store.bubbles || [];
  if (body.activeOnly) bubbles = bubbles.filter(b => b.status === 'active');
  if (body.withDeadlineOnly) bubbles = bubbles.filter(b => b.deadline);
  return [{ json: { bubbles, syncedAt: store.bubblesSyncedAt || null } }];
}

if (action === 'markBubbleDoneLocal') {
  if (store.bubbles) {
    const b = store.bubbles.find(x => x.id === body.id);
    if (b) b.status = 'done';
  }
  return [{ json: { ok: true } }];
}

// ── User data actions (require sessionId) ──
if (!sessionId) return [{ json: { error: 'no sessionId' } }];

if (!store.u) store.u = {};
if (!store.u[sessionId]) store.u[sessionId] = {};

if (action === 'get') {
  const u = store.u[sessionId];
  const reports = (store.reports || []).filter(r => !r.read);
  (store.reports || []).forEach(r => { r.read = true; });
  // merge alfa transactions into finance list (read-only items, source='alfa')
  const userFin = u.finance || [];
  const alfaFin = (store.alfaTx || []).map(tx => ({
    id: tx.id,
    type: tx.direction || (tx.type === 'income' ? 'in' : 'out'),
    amount: tx.amount,
    text: (tx.direction === 'in' ? '💰 Поступление' + (tx.sender ? ' от ' + tx.sender : '') : (tx.category || '❓ нужна категория')) + ' — ' + (tx.purpose || '').slice(0, 60),
    date: tx.isoDate || new Date().toISOString().slice(0,10),
    d: tx.txDate || '',
    category: tx.category || null,
    mcc: tx.mcc || null,
    purpose: tx.purpose || '',
    account: tx.account || null,
    source: 'alfa'
  }));
  const finance = [...alfaFin, ...userFin].sort((a, b) => (b.date || '').localeCompare(a.date || ''));
  return [{ json: {
    tasks:    u.tasks    || [],
    notes:    u.notes    || [],
    sport:    u.sport    || [],
    projects: u.projects || [],
    calendar: u.calendar || [],
    content:  u.content  || [],
    ideas:    u.ideas    || [],
    finance,
    bubbles:  store.bubbles || [],
    bubblesSyncedAt: store.bubblesSyncedAt || null,
    reports
  }}];
}

if (action === 'setAll') {
  const d = body.data || {};
  const cols = ['tasks','notes','sport','projects','calendar','content','ideas','finance'];
  for (const c of cols) {
    if (Array.isArray(d[c])) {
      // strip alfa items so they don't get duplicated when PWA writes back
      store.u[sessionId][c] = c === 'finance' ? d[c].filter(x => x.source !== 'alfa') : d[c];
    }
  }
  return [{ json: { ok: true } }];
}






return [{ json: { error: 'unknown action' } }];
